slow_assignment.solution:
Example slow_assignment_dec (m : nat) : decorated :=
  <{
    {{ X = m }}
      Y := 0
    {{ X = m /\ Y = 0 }} ->> {{ X + Y = m }}
      ;while X <> 0 do
        {{ X + Y = m /\ X <> 0 }} ->> {{ (X - 1) + (Y + 1) = m }}
          X := X - 1
        {{ X + (Y + 1) = m }}
          ;Y := Y + 1
        {{ X + Y = m }}
      end
    {{ X + Y = m /\ X = 0 }} ->> {{ Y = m }}
  }>.

Theorem slow_assignment : forall m,
  outer_triple_valid (slow_assignment_dec m).
Proof.
  verify.
Qed.

parity.solution:
Definition parity_dec (m:nat) : decorated :=
  <{
    {{ X = m }} ->> {{ parity X = parity m }}
      while 2 <= X do
        {{ parity X = parity m /\ 2 <= X }}
          ->> {{ parity (X - 2) = parity m }}
          X := X - 2
        {{ parity X = parity m }}
      end
    {{ parity X = parity m /\ ~(2 <= X) }}
      ->> {{ X = parity m }}
  }>.

Theorem parity_outer_triple_valid : forall m,
  outer_triple_valid (parity_dec m).
Proof.
  verify.
  - (* loop body *) rewrite <- H. apply parity_ge_2. omega.
  - (* post *) rewrite <- H. symmetry. apply parity_lt_2. omega.
Qed.

sqrt.solution:
Definition sqrt_dec (m:nat) : decorated :=
  <{
    {{ X = m }} ->> {{ X = m /\ 0 * 0 <= m }}
      Z := 0
    {{ X = m /\ Z * Z <= m }}
      ;while (Z+1) * (Z+1) <= X do
        {{ X = m /\ Z * Z <= m /\ (Z+1)*(Z+1) <= X }}
          ->> {{ X = m /\ (Z+1)*(Z+1) <= m }}
          Z := Z + 1
        {{ X = m /\ Z * Z <= m }}
      end
    {{ X = m /\ Z * Z <= m /\ ~((Z+1)*(Z+1) <= X) }}
      ->> {{ Z * Z <= m /\ m < (Z+1) * (Z+1) }}
  }>.

Theorem sqrt_correct : forall m,
  outer_triple_valid (sqrt_dec m).
Proof.
  verify. all: omega.
Qed.

factorial_correct.solution:
Example factorial_dec (m:nat) : decorated :=
  <{
    {{ X = m }}
      Y := 1
    {{ X = m /\ Y = 1 }} ->> {{ Y * fact X = fact m }}
      ;while X <> 0 do
        {{ Y * fact X = fact m /\ X <> 0 }}
          ->> {{ (Y * X) * fact (X - 1) = fact m }}
          Y := Y * X
        {{ Y * fact (X - 1) = fact m }}
          ;X := X - 1
        {{ Y * fact X = fact m }}
      end
    {{ Y * fact X = fact m /\ X = 0 }} ->> {{ Y = fact m }}
  }>.

Theorem factorial_correct: forall m,
  outer_triple_valid (factorial_dec m).
Proof.
  verify.
  - (* loop body *) destruct (st X) eqn:?.
    + omega.
    + simpl. rewrite <- minus_n_O. ring_simplify. omega.
  - (* postcondition *) simpl in *. omega.
Qed.
